# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

import flask
import graphene
from flask_graphql import GraphQLView

# --- Mock Data ---
products_db = {
    "P001": {"id": "P001", "name": "Wireless Headphones", "description": "High-quality sound, comfortable fit.", "price": 99.99, "category_id": "C001"},
    "P002": {"id": "P002", "name": "Smartwatch X", "description": "Track your fitness, receive notifications.", "price": 199.99, "category_id": "C002"},
    "P003": {"id": "P003", "name": "USB-C Hub", "description": "Expand your laptop's connectivity.", "price": 29.99, "category_id": "C003"},
    "P004": {"id": "P004", "name": "Gaming Mouse", "description": "Precise tracking, customizable buttons.", "price": 49.99, "category_id": "C003"},
}

categories_db = {
    "C001": {"id": "C001", "name": "Audio"},
    "C002": {"id": "C002", "name": "Wearables"},
    "C003": {"id": "C003", "name": "Computer Accessories"},
}

reviews_db = [
    {"id": "R001", "product_id": "P001", "user_id": "U001", "rating": 5, "comment": "Amazing sound quality, love them!"},
    {"id": "R002", "product_id": "P001", "user_id": "U002", "rating": 4, "comment": "Good headphones, a bit pricey."},
    {"id": "R003", "product_id": "P002", "user_id": "U003", "rating": 5, "comment": "Best smartwatch I've owned."},
    {"id": "R004", "product_id": "P003", "user_id": "U001", "rating": 3, "comment": "It works, but feels a bit cheap."},
    {"id": "R005", "product_id": "P004", "user_id": "U004", "rating": 5, "comment": "Perfect for gaming, very responsive."},
]

# --- Graphene Schema ---

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()

class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()

class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    category = graphene.Field(Category)
    reviews = graphene.List(Review)

    def resolve_category(self, info):
        return categories_db.get(self.category_id)

    def resolve_reviews(self, info):
        return [r for r in reviews_db if r["product_id"] == self.id]

class Query(graphene.ObjectType):
    product = graphene.Field(Product, id=graphene.ID(required=True))
    products = graphene.List(Product)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    categories = graphene.List(Category)
    review = graphene.Field(Review, id=graphene.ID(required=True))
    reviews = graphene.List(Review, product_id=graphene.ID())

    def resolve_product(self, info, id):
        return products_db.get(id)

    def resolve_products(self, info):
        return list(products_db.values())

    def resolve_category(self, info, id):
        return categories_db.get(id)

    def resolve_categories(self, info):
        return list(categories_db.values())

    def resolve_review(self, info, id):
        return next((r for r in reviews_db if r["id"] == id), None)

    def resolve_reviews(self, info, product_id=None):
        if product_id:
            return [r for r in reviews_db if r["product_id"] == product_id]
        return reviews_db

schema = graphene.Schema(query=Query)

# --- Flask App ---
app = flask.Flask(__name__)

app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True # Enable GraphiQL for introspection and testing
    )
)

if __name__ == "__main__":
    app.run(debug=True)